INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('936f3648-b521-428f-86f1-a3b7da367c4f', '3496d3cd-c86b-49ad-b8ba-0156fe4283ae', 'Edit, Test, Launch', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('4dd11cac-db85-4f59-b64a-16f509d311c9', 'c057eb1c-8957-43df-9e6e-d25947d1d57f', 'The script makes assumptions about its environment (paths, dependencies, env vars) that are not true on the server', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('885ec6ba-445f-4874-b278-b8df7b2c7027', 'c057eb1c-8957-43df-9e6e-d25947d1d57f', 'Production servers cannot run Python scripts', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('04d0071a-14a6-4dcb-afc5-cde0e7ffbbad', 'c057eb1c-8957-43df-9e6e-d25947d1d57f', 'Local scripts are slower than production systems', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('3bf12c7f-850b-427f-9828-2ad8ed10fdee', 'c057eb1c-8957-43df-9e6e-d25947d1d57f', 'Production code must be written in a compiled language', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('17b4eede-f92e-4d81-a40f-ad9072f4941a', '6f5100ae-436b-415b-81ef-2a45528e2e0f', 'Git history makes the secret permanent : anyone who can clone the repo gets your credentials, even after you delete the file later', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('c1bd502b-be67-4310-ac1e-398b31155aeb', '6f5100ae-436b-415b-81ef-2a45528e2e0f', '`.env` files are too large for git to handle', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('6e3a67a7-92e0-4251-babd-d65c2ef1a341', '6f5100ae-436b-415b-81ef-2a45528e2e0f', 'Git cannot parse the `KEY=value` syntax', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('79cda386-183d-46a0-b3e0-9652d29e4606', '6f5100ae-436b-415b-81ef-2a45528e2e0f', '`.env` files are read-only on Linux servers', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('297816e2-020a-454f-ad96-6123c7d25055', 'e1ed4c53-fd5a-4101-92c8-9c35d1d245ca', 'It documents the variable NAMES (with placeholder values) so a teammate cloning the repo knows what to set in their own `.env`', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('a91ade7d-f876-422e-99af-0ab14922cdfe', 'e1ed4c53-fd5a-4101-92c8-9c35d1d245ca', 'It is the file your code actually reads at runtime', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('6b1b2314-714d-4da6-b2f3-e1f922f3ca1c', 'e1ed4c53-fd5a-4101-92c8-9c35d1d245ca', 'It contains the real production secrets that the deployed pipeline uses', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('89e6fb21-a11d-43f8-99e5-62e16b7bead2', 'e1ed4c53-fd5a-4101-92c8-9c35d1d245ca', 'It is an automatic backup that python-dotenv creates', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('38bd3843-27a5-4a97-8fa4-b887a7d85e1c', 'd76e5725-6582-4c04-a06d-0fee9c7da2ef', 'One place to change a variable name, one place to add validation : the rest of the code does `from config import API_KEY`', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('645149d2-4267-426f-874e-d1ad6f0d54ab', 'd76e5725-6582-4c04-a06d-0fee9c7da2ef', '`config.py` runs faster than `os.environ.get`', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('b280c940-27c0-4517-aa0e-1ff900143fc7', 'd76e5725-6582-4c04-a06d-0fee9c7da2ef', 'It is the only legal way to read env vars in Python 3.10+', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('96f64135-25a1-4ce4-bba6-9b1c860b3fcd', 'd76e5725-6582-4c04-a06d-0fee9c7da2ef', '`config.py` automatically encrypts the values it reads', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('b6caa601-a8ba-4d7a-8ea6-7b0bd81e0ad1', 'ca10dedb-9aa1-4a68-b700-4830132a791f', 'You cannot test the cleaning or calculation logic without a real CSV file on disk : every test needs filesystem setup', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('d09d3cf4-5a02-43d6-8e1a-2ca5863fcef6', 'ca10dedb-9aa1-4a68-b700-4830132a791f', 'The function is too long for Python to compile', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('10a14663-d991-438f-b63f-833d04677887', 'ca10dedb-9aa1-4a68-b700-4830132a791f', 'Python has a 50-line per-function limit', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('32c06621-cc74-445c-bd52-56c0ea6261d2', 'ca10dedb-9aa1-4a68-b700-4830132a791f', 'It uses too much memory by default', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('c9f4d894-2ca7-4354-8c7c-4e39c807f88b', '7934a467-8633-4397-ab36-5e9c0baff7be', 'As little as possible : just get data in or out, and leave validation, filtering, and business rules to pure functions', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('b887c621-c42e-4449-813c-50281a165f6c', '7934a467-8633-4397-ab36-5e9c0baff7be', 'Validate every field before returning, so callers do not have to', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('8747e0f4-3bba-45a3-a6ad-a22c3f5b78e1', '7934a467-8633-4397-ab36-5e9c0baff7be', 'Catch every possible exception silently and return an empty list', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('19ccdf65-bd2d-4bd0-badc-b3f5cbc79293', '7934a467-8633-4397-ab36-5e9c0baff7be', 'Log every step in detail so the operator can debug later', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('c7a1a3e9-e2a9-49c4-b28f-415da08fcc7d', '61990a80-5491-4e36-ab39-1abbd298d3ec', '`def double(x): return x * 2`', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('2036faa2-26f3-49e4-b396-c85ef47d1e3a', 'ea93d4d1-1b15-4e40-a91f-7bc0ed1ecde7', 'So different projects can pin different package versions without conflicts', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('b7ddddaf-2e89-4f66-a3db-41004a5301e0', 'ea93d4d1-1b15-4e40-a91f-7bc0ed1ecde7', 'To make Python run faster', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('36ba3262-ad2f-43d2-9dba-49de006f13f5', 'ea93d4d1-1b15-4e40-a91f-7bc0ed1ecde7', 'To save disk space', false) ON CONFLICT DO NOTHING;
