INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('21739705-597a-4c99-ac08-cdd612509b1a', '2e438c79-9224-4de6-be01-172607de64ef', 'So projects can use different package versions without breaking each other', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('e9ec9529-a0ca-4c6f-9664-5681d4459335', '2e438c79-9224-4de6-be01-172607de64ef', 'To make Python run faster', false) ON CONFLICT DO NOTHING;
