INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('626dcaf3-826c-43c9-9e58-90c87e753a12', '2e438c79-9224-4de6-be01-172607de64ef', 'Python will not run scripts that are not in a venv', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('84e5db98-13af-405a-b824-e4d14310112e', 'c7932f63-7890-4c09-b087-88e539fdba1c', 'Reinstall Python', false) ON CONFLICT DO NOTHING;
