INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('7122aaea-4711-4973-aaa5-492d3fb43d8d', 'c7932f63-7890-4c09-b087-88e539fdba1c', 'Run `pip install pandas` again with sudo', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('f099ccf6-caa2-424c-aebf-386ee6c7745a', '35fe694c-9157-482f-9155-8a00fd0e10b6', '[1, 2, 3] : `a` and `b` point to the same list', true) ON CONFLICT DO NOTHING;
