INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('41c21216-1114-4bfe-b42d-9571c4057685', '35fe694c-9157-482f-9155-8a00fd0e10b6', '[3, 1, 2] : append puts the new item at the front', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('421720cc-6e3e-4817-9536-d059f7afa706', '35fe694c-9157-482f-9155-8a00fd0e10b6', 'Error : you cannot change `a` after assigning it to `b`', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('db8ad332-a253-4422-83ed-38c49d042227', '743f8c65-2cb7-4e69-94f9-1f17cc4eb19b', 'True : 0.1 plus 0.2 is 0.3', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('19236ab0-f00c-44fa-82c4-336a58a3d834', '743f8c65-2cb7-4e69-94f9-1f17cc4eb19b', 'False : Python stores decimals in binary, so the sum is slightly off (about 0.30000000000000004)', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('283d7c8c-b614-4039-b772-02662560fd54', '743f8c65-2cb7-4e69-94f9-1f17cc4eb19b', 'True, but only on macOS', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('08eaa61a-a3dc-4a43-aeb6-96ae6e4237e2', '743f8c65-2cb7-4e69-94f9-1f17cc4eb19b', 'Error : you cannot compare floats with `==`', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('026a4253-87a8-45ed-812d-7be13c381cc6', '2977a24c-d1ab-4c3d-a16f-b84e5a0ff397', '`if my_list:` (an empty list counts as False)', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('2168c4fe-68c0-4619-bc74-c58c6866cad6', '2977a24c-d1ab-4c3d-a16f-b84e5a0ff397', '`if my_list != []:`', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('962947ff-1ce3-486a-b6ec-85d68103b9d3', '2977a24c-d1ab-4c3d-a16f-b84e5a0ff397', '`if my_list is not None:`', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('c5afca2f-9535-4d6c-b6ef-529893c3e4ce', '2977a24c-d1ab-4c3d-a16f-b84e5a0ff397', '`if my_list.size() > 0:`', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('d33ca619-4939-4d5d-bb87-b0ffaf8f4804', 'fa0c8d39-cad9-4df0-a0fe-7d853ee940f4', 'Skip the rest of this iteration and start the next one', true) ON CONFLICT DO NOTHING;
