INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('afbb0aca-83d5-496c-a6ab-43880f475160', 'fa0c8d39-cad9-4df0-a0fe-7d853ee940f4', 'Restart the loop from the beginning', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('9a09007d-600c-4232-80c4-f07e9c2efd7f', 'fa0c8d39-cad9-4df0-a0fe-7d853ee940f4', 'Pause the loop until the user presses a key', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('db830a45-73b4-4464-8444-a1a83d0587ae', '5aefa119-24f9-4e77-8936-0c67f00a0edd', 'Be both an importable library AND a script you can run directly', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('c6efa039-af0e-4a59-bd27-cab205296728', '5aefa119-24f9-4e77-8936-0c67f00a0edd', 'Stop other people from importing the file', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('cb6a6697-07ea-4660-bd2b-28f00e94ae7b', '5aefa119-24f9-4e77-8936-0c67f00a0edd', 'Make the file run faster', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('8da7952b-6954-444f-b31a-88817c8d3184', '5aefa119-24f9-4e77-8936-0c67f00a0edd', 'Mark the file as the only entry point in the project', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('5cf10b06-8415-4f61-a6e6-303720c832b7', '2013c62f-ab91-4ecf-9bd9-1994151160d4', 'The same list `[]` is reused on every call, so previous calls leave their items in it', true) ON CONFLICT DO NOTHING;
