INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('323426cd-31c9-4dc1-94f6-b4168817b4af', '2013c62f-ab91-4ecf-9bd9-1994151160d4', 'It runs slower than using `None`', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('e21d8391-74b4-4022-ae85-e070adf71556', '2013c62f-ab91-4ecf-9bd9-1994151160d4', 'It hides Python''s built-in `list` type', false) ON CONFLICT DO NOTHING;
