INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('03144de0-7d98-40f4-a21b-5d34efc40d85', '610a218b-03cc-4f7b-a849-de6c394b5a0a', 'Only when you run with the `--strict` flag', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('1c226817-2bd4-416f-9576-be0f59745cf3', '610a218b-03cc-4f7b-a849-de6c394b5a0a', 'Only for built-in types like `int` and `str`', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('7275e444-b7b3-4b1c-9c9c-48a70da04d66', '581a071f-c3c2-4a06-9788-f6b2971b7168', 'The function takes a string `name` and returns a string', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('295dc8b9-72eb-4522-8c1d-785cd3372a13', '581a071f-c3c2-4a06-9788-f6b2971b7168', 'The function takes a string `name` and returns nothing', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('f759c956-50fa-4989-be18-1f277e8ba362', '581a071f-c3c2-4a06-9788-f6b2971b7168', 'The function only accepts strings shorter than the value of `str`', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('7a3b59d9-2050-4df6-9268-40ef9a247d08', '581a071f-c3c2-4a06-9788-f6b2971b7168', 'The function will throw an error if `name` is not a string', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('f13f2347-95ed-4fec-a530-bc8ac51882cb', '0711d8ef-89ff-4133-a20b-90b2608f0119', 'Nothing : the scheduler types the answer for you', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('c7542a38-6ed6-41a7-8888-f61d5844c5e6', '0711d8ef-89ff-4133-a20b-90b2608f0119', 'The script pauses forever waiting for someone to type, because no person is at the keyboard', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('c447d2db-5fd8-4e2e-8290-bd2e433c130d', '0711d8ef-89ff-4133-a20b-90b2608f0119', 'The script crashes immediately with a `SyntaxError`', false) ON CONFLICT DO NOTHING;
