INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('d0a6250e-a8e6-4cf1-86e5-4b2431dbcd5e', '0f80e2c5-5856-42fa-a1ae-9affcf13d3c1', 'It generates a `--help` message, checks types, and gives clear errors when an argument is missing or wrong', true) ON CONFLICT DO NOTHING;
