INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('22e4463e-bdb6-41ae-afd6-4c9717877e10', '0f80e2c5-5856-42fa-a1ae-9affcf13d3c1', 'It is the only way to read command-line arguments in Python 3.10+', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('9d349f42-9416-4d74-a1c2-dac36306a859', '0f80e2c5-5856-42fa-a1ae-9affcf13d3c1', 'It encrypts the arguments so other users on the machine cannot see them', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('fc93daaa-2914-47e0-965a-0af7cf8bdb12', '523d2bf8-56ad-4de4-a90d-09642f652089', '`SyntaxError` : Python could not even parse the code, so it stopped before running anything', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('208add33-ac55-4b07-8688-14ddef4d9c6e', '523d2bf8-56ad-4de4-a90d-09642f652089', '`RuntimeError` : the code ran and then failed', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('03df3679-37f4-4c94-befa-330afbb8af45', '523d2bf8-56ad-4de4-a90d-09642f652089', '`KeyError` : Python could not find the colon', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('2ec6c05c-8410-4450-b55c-e5857ec691df', '523d2bf8-56ad-4de4-a90d-09642f652089', '`TypeError` : Python expected a different type', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('3010d154-4f81-4b76-9417-753731d224f7', '9612a75c-9c1a-448b-a838-d5e85d937adb', 'The very last line at the bottom', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('cd23cb86-a7d7-465b-8b25-1d6643edeb3e', '9612a75c-9c1a-448b-a838-d5e85d937adb', 'The first line at the top', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('6f3b151a-1ec2-4e0c-ac8b-c02fa522bdba', '9612a75c-9c1a-448b-a838-d5e85d937adb', 'Always exactly in the middle of the traceback', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('796d6c88-0c39-4761-a7e6-0b7b41f7f2a9', '9612a75c-9c1a-448b-a838-d5e85d937adb', 'On the line that says `Traceback (most recent call last)`', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('8fe2cd48-b437-405d-9b11-0c9dd8d8978f', '663b75e0-d698-455d-bf41-1c78c9638351', 'Step Into : it pauses on the first line inside the function', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('4544f9f9-5ab5-40a7-8e3c-d3ad60fbd554', '663b75e0-d698-455d-bf41-1c78c9638351', 'Step Over : it runs the function and pauses on the next line of your file', false) ON CONFLICT DO NOTHING;
