INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('90d22e2b-d693-44f4-9c1d-964711340eaf', '663b75e0-d698-455d-bf41-1c78c9638351', 'Restart : you have to re-run from the beginning to enter a function', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('463cd73f-283e-4459-833f-ce78dac4bce7', 'd4df1269-4e39-4ee2-a92d-2f3d3060ffad', '`logging` adds severity levels (INFO / WARNING / ERROR) and timestamps, and can write to a file. `print` just goes to the screen and is often lost in production.', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('52868ca2-8d73-42b6-9fab-7283fca0352b', 'd4df1269-4e39-4ee2-a92d-2f3d3060ffad', '`logging` runs faster than `print`', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('0a98024b-8970-4782-8f76-1a80be44bd9c', 'd4df1269-4e39-4ee2-a92d-2f3d3060ffad', '`print` is removed in Python 3.13', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('b9736d2c-05a0-450b-a04e-b26c399b17ef', 'd4df1269-4e39-4ee2-a92d-2f3d3060ffad', '`logging` automatically sends an email when there is an error', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('1c46665d-9db6-498d-bd72-5bf748094009', '896ff6ae-9141-4597-ace4-cbe1c69e4fcc', 'INFO : it is a normal expected event', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('94951635-efe4-4ee9-803a-c772731fbac1', '896ff6ae-9141-4597-ace4-cbe1c69e4fcc', 'ERROR : every visible message should be an ERROR for safety', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('ed5ec939-ce7b-4f62-aefb-54bf0a211999', '896ff6ae-9141-4597-ace4-cbe1c69e4fcc', 'DEBUG : login messages are too noisy for production', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('01923ed3-c906-4aa6-8f61-be0dcd8015ee', '896ff6ae-9141-4597-ace4-cbe1c69e4fcc', 'CRITICAL : a successful login is a high-impact event', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('64d9f59b-d82c-4b0c-9f01-7239ceef8c27', 'b642e5e2-96d7-43ab-908c-cd201eb9905e', '`with` always closes the file when the block ends, even if an error happens inside', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('1b221d00-0fa9-4405-b9cf-7466604c6543', 'b642e5e2-96d7-43ab-908c-cd201eb9905e', '`with` is the only way to read text files in Python 3', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('13c5517f-d3e0-477a-adc4-37871baf2972', 'b642e5e2-96d7-43ab-908c-cd201eb9905e', '`with` runs the file reading in the background so your script does not block', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('64e855b1-36ba-47b0-b8dc-660659f0a3a8', 'b642e5e2-96d7-43ab-908c-cd201eb9905e', '`with` automatically encrypts the file contents', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('65cb3c17-35f6-4bf9-911c-38014dd6687b', '79337641-e262-4619-9979-3791dad28c60', '`Path` uses the right slash for the OS your code runs on, so the same code works on macOS, Linux, AND Windows', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('9edadcd4-a26d-4222-a3f9-360ae2064144', '79337641-e262-4619-9979-3791dad28c60', '`Path` runs faster than string concatenation', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('20ff9e02-3107-4b68-939c-3e2aac6f2f7e', '79337641-e262-4619-9979-3791dad28c60', '`Path` automatically creates the file if it does not exist', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('fb483f10-8479-4d96-bd52-df0913429256', '79337641-e262-4619-9979-3791dad28c60', 'String paths stopped working in Python 3.12', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('725f1aa6-5a02-4dda-95df-ac4893444d79', '6f43ca67-6631-46f3-84a2-917132d0bb0b', 'Every value from a CSV is a string, so `row["age"]` is `"30"`, not `30`. Fix: `int(row["age"]) + 1`', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('661b5e78-412d-46ea-8dfc-f5a21bb2bf9d', '6f43ca67-6631-46f3-84a2-917132d0bb0b', 'The `+` operator is broken for strings; use `next_year = row["age"] - 1` instead', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('5e3c8512-4d1f-4de2-b5a3-976deb91e02f', '6f43ca67-6631-46f3-84a2-917132d0bb0b', '`csv.DictReader` is broken in Python 3; switch to `csv.reader`', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('b0804e49-2994-47ea-ae3d-2a4bc0bfe25a', '6f43ca67-6631-46f3-84a2-917132d0bb0b', 'You need to add `from __future__ import string_arithmetic`', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('ff2e651e-6697-4dc1-9923-c34a21978ddf', '61990a80-5491-4e36-ab39-1abbd298d3ec', '`def double(x): print(x); return x * 2` (prints to the screen)', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('eb31ed1a-e2f9-4266-8b7c-47270cc6bf87', '61990a80-5491-4e36-ab39-1abbd298d3ec', '`def double(x): with open("log.txt", "a") as f: f.write(str(x)); return x * 2` (writes to disk)', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('8a34a3e2-8427-4237-a52e-e2e720541021', '61990a80-5491-4e36-ab39-1abbd298d3ec', '`def double(x): global counter; counter += 1; return x * 2` (mutates a global)', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('f2635d53-0e26-423e-8018-84e9779f284b', '492ee5d0-0d31-4932-8117-0d0e934b9cf4', 'No : refactor it to a plain `clean(df)` function. A stateless class is ceremony around a function call', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('44ce5dd0-31c6-4969-8653-283aafc45f12', '492ee5d0-0d31-4932-8117-0d0e934b9cf4', 'Yes : classes are always preferred over functions in production code', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('72acbc90-b5e2-40b5-9cdb-c0719494a92d', '492ee5d0-0d31-4932-8117-0d0e934b9cf4', 'Yes, but only after adding three more methods so the class is not lonely', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('53391992-81d3-4d8d-b68c-9e628985449b', '492ee5d0-0d31-4932-8117-0d0e934b9cf4', 'No, but only if the cleaning is fewer than 20 lines', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('671cdd8e-8aaf-4209-a336-1c1a8d29a2aa', '87545196-6ca2-4e11-bbc9-ed5e0ca4caf9', '`__init__`, `__repr__`, and equality methods, derived from your field declarations', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('b545d965-78d9-4cba-b2aa-357dff709413', '87545196-6ca2-4e11-bbc9-ed5e0ca4caf9', 'A web API endpoint exposing the class fields as JSON', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('e5a9edd7-333d-46ae-a857-f6ee2f03e2f6', '87545196-6ca2-4e11-bbc9-ed5e0ca4caf9', 'A SQL table matching the class field names', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('6d9a58ec-5035-4b3f-ad6d-6138c6d9a634', '87545196-6ca2-4e11-bbc9-ed5e0ca4caf9', 'Static methods that validate every input value', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('41c26e8f-649e-4b17-b2fa-ed3bd79b42a6', '5134b6ee-1766-4455-8086-08c9e1bd5b85', 'The editor knows what fields exist; typos like `product.prize` are flagged before you run the code', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('6a021c64-cbbe-47e4-946e-5c1039cf3964', '5134b6ee-1766-4455-8086-08c9e1bd5b85', 'Dot access runs faster than dict access', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('e5657850-a390-4c0c-a138-1853640015c3', '5134b6ee-1766-4455-8086-08c9e1bd5b85', 'Dictionaries are deprecated in Python 3.12', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('1a71c214-bdfb-489b-9620-1658ce17566d', '5134b6ee-1766-4455-8086-08c9e1bd5b85', 'Dot access uses less memory than dict access', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('a6003871-ada2-463b-955b-9b55f887b3d8', '370496da-b286-456b-95fc-71c30a1ae7b4', 'Runs right AFTER the auto-generated `__init__` finishes : the standard place to put validation rules like `if price < 0: raise ValueError`', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('6abf34f9-32c5-4ece-a082-f3c222f6d055', '370496da-b286-456b-95fc-71c30a1ae7b4', 'Replaces `__init__` entirely : you cannot have both', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('10f7f31d-559e-4498-8fce-066782db55c0', '370496da-b286-456b-95fc-71c30a1ae7b4', 'Runs BEFORE `__init__` and decides whether the object should be built', false) ON CONFLICT DO NOTHING;
