INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('950c80a5-d053-4b70-bd9a-cb1ef68f7ffd', '0b15e416-2aa9-4bcf-b27f-644fad65ec68', '`from dataclasses import asdict` and call `asdict(product)`', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('f71d3e80-10b5-43f2-94f6-fdb6080667f6', '0b15e416-2aa9-4bcf-b27f-644fad65ec68', '`product.to_json()` : every dataclass auto-defines this method', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('1094ff71-18e5-4bcf-a6bc-d7ce044386f0', '0b15e416-2aa9-4bcf-b27f-644fad65ec68', '`dict(product)` : Python auto-converts dataclasses on cast', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('414a3629-8313-43c0-875a-9ad3047ae9c6', '0b15e416-2aa9-4bcf-b27f-644fad65ec68', '`json.dumps(product)` : dataclasses are JSON-serialisable by default', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('691737a1-5763-4ad0-9f87-1ca5af88e0e7', 'ebb21bdf-def9-4d6e-8e41-9ad6398c807c', 'Builds a NEW dict copying every key from `row`, then overrides `price`. The original `row` is untouched.', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('02945c4a-9376-402d-bd4c-f8b073fea98a', 'ebb21bdf-def9-4d6e-8e41-9ad6398c807c', 'Modifies `row` in place by setting `row["price"] = new_price`', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('82cd32a7-5c72-42cb-ada0-35f6739c70ac', 'ebb21bdf-def9-4d6e-8e41-9ad6398c807c', 'Deletes the `price` key from `row`', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('93b67e8a-c1fc-4dd8-8e2f-5925ac51fadf', 'ebb21bdf-def9-4d6e-8e41-9ad6398c807c', 'Wraps `row` in a new immutable type that cannot be changed afterwards', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('b055032c-3fc7-48f2-8be1-b4165e7de03d', '33a42390-e176-48ec-8b97-952629855e89', '`TypeError: NoneType object is not iterable`, raised by the NEXT function in the chain (the one that received `None`)', true) ON CONFLICT DO NOTHING;
