INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('61806493-7dc1-4882-948b-854f60ccbb4c', '33a42390-e176-48ec-8b97-952629855e89', 'The function returns the last expression evaluated, so the chain still works', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('08545e73-6a55-4d77-aedb-c750538e4d58', '33a42390-e176-48ec-8b97-952629855e89', 'Nothing happens : `None` is treated as an empty list by the next function', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('8c08725e-1816-427e-9453-d6981537b31f', 'c5127c17-8a53-4ac5-a4b2-91f4f0144d56', 'Decorate a function with `@pytest.fixture` and have it return the list, then add the function name as a parameter to each test', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('9cc6178e-8e26-4d8e-8192-e86d62b4d677', 'c5127c17-8a53-4ac5-a4b2-91f4f0144d56', 'Define the list as a global variable at the top of the test file', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('fcbb4daf-19b2-4860-8822-fccbe798ba0a', 'c5127c17-8a53-4ac5-a4b2-91f4f0144d56', 'Put it in a `setUp` method on a test class (Java/JUnit style)', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('7a0518a4-8439-42df-8fc1-e1e40ba0c53f', 'c5127c17-8a53-4ac5-a4b2-91f4f0144d56', 'Pass the list via the `pytest -d` command-line flag', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('93d5bb35-de2d-4f4d-805b-b8e37022c71f', '4a758310-c90c-4599-b227-723ba377884f', '`@pytest.mark.parametrize("input, expected", [...])` : each input becomes a separately-named test in the output', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('19f902ba-1c95-434f-be87-a6ef38f4b8c8', '4a758310-c90c-4599-b227-723ba377884f', 'A `for` loop inside a single test function (the loop fails on the first bad assert)', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('eb14e684-3c15-4c3d-9b0c-aa43a401231b', '4a758310-c90c-4599-b227-723ba377884f', 'Five separate test functions copy-pasted with different data', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('e177ea97-615d-4978-8196-971a62c9e622', '4a758310-c90c-4599-b227-723ba377884f', 'A `conftest.py` file with five separate fixtures', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('a045d9a2-a1e2-455e-9b47-0b09346bb3bf', '8a6177d3-8b08-4ca9-8026-515e848c82a1', '`format` first, then `check --fix` : the formatter rewrites layout, then the linter evaluates the FINAL layout for issues', true) ON CONFLICT DO NOTHING;
