INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('154bc643-b64e-466d-b5ef-78e969e5dc6e', '8a6177d3-8b08-4ca9-8026-515e848c82a1', 'It does not matter : the two tools are completely independent', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('daa09ada-b9d0-461e-937e-36b1a960dc12', '8a6177d3-8b08-4ca9-8026-515e848c82a1', 'Always run them in parallel for speed', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('4d753461-8aea-4caa-8b7f-e19e7df4efc1', 'f47ccd9c-9537-43b9-8d35-1c46fbcf197f', 'Python raises `ValueError` immediately. Dataclasses refuse to compile with mutable defaults; the fix is `tags: list = field(default_factory=list)`', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('0c9a447c-9865-4812-9276-aa8e92253917', 'f47ccd9c-9537-43b9-8d35-1c46fbcf197f', 'It works fine : every instance gets a fresh empty list', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('43b90de4-6609-4ad3-9775-fc0438e2179d', 'f47ccd9c-9537-43b9-8d35-1c46fbcf197f', 'It works fine, but only if you also write a custom `__init__`', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('2cf9fef5-d392-44ef-9acd-35208c3ca6ea', 'f47ccd9c-9537-43b9-8d35-1c46fbcf197f', 'It silently shares the same list across every instance, like a regular function default', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('4a85caf6-86b3-4796-a27d-f66d5b915323', 'd515f2ea-fef0-4b9c-866e-438b9f132837', 'Python imports your local file instead of the standard-library module : `import csv` finds your file first, and `csv.DictReader` then breaks with confusing `AttributeError`s', true) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('2717a65f-22f0-4889-81ab-bdf4e1b28554', 'd515f2ea-fef0-4b9c-866e-438b9f132837', 'The name `csv` is a reserved word in Python 3.10+', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('8b5eb6dd-d4f4-4912-a468-660e2f1b3a1c', 'd515f2ea-fef0-4b9c-866e-438b9f132837', 'It conflicts with the file extension `.csv` so the filesystem confuses the two', false) ON CONFLICT DO NOTHING;
INSERT INTO public.choices (id, question_id, body, is_correct) VALUES ('cf3c6197-5554-4e91-a182-8521945efb2e', 'd515f2ea-fef0-4b9c-866e-438b9f132837', 'Pylint warns you about reserved module names and refuses to lint the file', false) ON CONFLICT DO NOTHING;
